n = len(l)
    if n < 3:
        return False

    l.sort()
    for i in range(n - 2):
        left, right = i + 1, n - 1
        while left < right:
            s = l[i] + l[left] + l[right]
            if s == 0:
                return True
            if s < 0:
                left += 1
            else:
                right -= 1
    return False
